import{_ as s,o as a,c as e,a0 as t}from"./chunks/framework.CEW4uG-d.js";const c=JSON.parse('{"title":"Whitelisting Domains","description":"","frontmatter":{},"headers":[],"relativePath":"guide/whitelist.md","filePath":"guide/whitelist.md"}'),l={name:"guide/whitelist.md"};function n(h,i,p,o,d,r){return a(),e("div",null,[...i[0]||(i[0]=[t(`<h1 id="whitelisting-domains" tabindex="-1">Whitelisting Domains <a class="header-anchor" href="#whitelisting-domains" aria-label="Permalink to &quot;Whitelisting Domains&quot;">​</a></h1><p>Sometimes, a blocklist may cause a legitimate website or service you use (such as a marketing email referral link or a gaming service connection) to stop loading.</p><p>BlockGuard allows you to whitelist specific domains to ensure they are never filtered.</p><hr><h2 id="whitelist-commands" tabindex="-1">Whitelist Commands <a class="header-anchor" href="#whitelist-commands" aria-label="Permalink to &quot;Whitelist Commands&quot;">​</a></h2><p>Manage your custom whitelist using the following commands:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Add a domain to the whitelist</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> blockguard</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> whitelist</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> example.com</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># List all currently whitelisted domains</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> blockguard</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> whitelist</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> list</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Remove a domain from the whitelist</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> blockguard</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> whitelist</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> remove</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> example.com</span></span></code></pre></div><hr><h2 id="subdomain-matching-rules" tabindex="-1">Subdomain Matching Rules <a class="header-anchor" href="#subdomain-matching-rules" aria-label="Permalink to &quot;Subdomain Matching Rules&quot;">​</a></h2><p>When you whitelist a domain, it applies recursively to all its subdomains.</p><ul><li>Whitelisting <code>example.com</code> will automatically allow: <ul><li><code>example.com</code></li><li><code>www.example.com</code></li><li><code>api.staging.example.com</code></li></ul></li></ul><hr><h2 id="applying-changes" tabindex="-1">Applying Changes <a class="header-anchor" href="#applying-changes" aria-label="Permalink to &quot;Applying Changes&quot;">​</a></h2><p>After modifying your whitelist, you must restart or reload BlockGuard to apply the changes to the engine:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> blockguard</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> stop</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> blockguard</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> start</span></span></code></pre></div><p><em>Alternatively, send SIGHUP to reload configs in-memory:</em></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> kill</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -HUP</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> $(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cat</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.blockguard/blockguard.pid</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div>`,17)])])}const g=s(l,[["render",n]]);export{c as __pageData,g as default};
